#define HEX5_HEX4_BASE     0xFF200030

#define LEDR_BASE          0xFF200000
#define SW_BASE            0xFF200040
#define KEY_BASE           0xFF200050
#define PS2_BASE           0xFF200100

/* ============================================================================
 * CONSTANTES DO JOGO
 * ============================================================================
 */

