#ifndef TYPES_H
#define TYPES_H

typedef enum { FACING_LEFT, FACING_RIGHT } Direcao;
typedef enum { ESTADO_INICIO, ESTADO_JOGANDO, ESTADO_PAUSADO, ESTADO_GAMEOVER, ESTADO_VITORIA } EstadoJogo;
typedef enum { ANIM_IDLE, ANIM_RUN, ANIM_JUMP, ANIM_SHOOT, ANIM_INTRO } AnimacaoEstado;

typedef struct {
    int x, y;
    int vx, vy;
    int no_chao;
    Direcao direcao;
    int vidas;
    int pontuacao;
    int invulneravel;
    int atacando;
    AnimacaoEstado anim_estado;
    int anim_frame;
    int anim_timer;
} Jogador;

typedef enum { COMPORTAMENTO_PARADO, COMPORTAMENTO_PATRULHA, COMPORTAMENTO_PERSEGUICAO } ComportamentoInimigo;

typedef struct {
    int x, y;
    int w, h;
    int vivo;
    int tipo;              /* 0=estatua passiva, 1=guarda nocivo, 2=atirador, 3=chefe */
    ComportamentoInimigo comportamento;
    int patrulha_min_x;
    int patrulha_max_x;
    int vx;
    Direcao direcao;
    int vida;
    int cooldown_tiro;
} Inimigo;

typedef struct {
    int x, y;
    int vx;
    int ativo;
    int dist_percorrida;
    int do_inimigo;
} Projetil;

typedef struct {
    int x;
    int largura;
} Gap;

typedef struct {
    int x;
    int largura;
} Lava;

typedef struct {
    int x, y;
    int largura;
    int altura;
} Plataforma;

typedef struct {
    int x, y;
    int coletado;
} Token;

typedef struct {
    int x, y;
    int w, h;
    int vivo;             /* 1 = presente no cenario */
    int explodindo;        /* 1 = tocando a animacao/aplicando dano da explosao */
    int frame_atual;        /* indice do frame de animacao (0 = intacto) */
    int timer_frame;        /* contagem de ticks no frame atual */
    int aplicou_dano;       /* garante que o dano em area seja aplicado uma unica vez */
} Barril;

#endif
#ifndef HARDWARE_H
#define HARDWARE_H

#include <stdint.h>

extern volatile short int *pixel_buffer_back;
extern int tecla_esquerda, tecla_direita, tecla_cima, tecla_atirar, tecla_reiniciar;

void desenha_pixel(int x, int y, short int cor);
void desenha_retangulo(int x, int y, int largura, int altura, short int cor);
void limpa_tela(short int cor);
void aguarda_swap_completo(void);
void inicializa_video(void);
void troca_buffers(void);

void processa_teclado(void);
int chave_sw0_ligada(void);

void atualiza_pontuacao_display(int pontuacao);
void atualiza_vidas_display(int vidas);
void atualiza_vidas_leds(int vidas);

#endif
